+    /// Convert a floating-point arithmetic result into a SQLite value.
+    ///
+    /// SQLite does not surface NaN; NaN is normalized to NULL while ±Inf remain REAL.
+    fn float_result_or_null(result: f64) -> Self {
+        if result.is_nan() {
+            Self::Null
+        } else {
+            Self::Float(result)
+        }
+    }
